INSERT INTO public.vocabulary (id, german_word, english_translation, article, plural, example_sentence, level, category, theme, french_translation, arabic_translation, ipa, synonyms, antonyms, word_family, verb_forms, frequency, difficulty_score, word_type, tags) VALUES
  (gen_random_uuid(), 'Strategie', 'strategy', 'die', 'die Strategien', 'Die Firma hat eine neue Strategie für den internationalen Markt entwickelt. — The company has developed a new strategy for the international market.', 'B2', 'business', 'Professional & Business', 'stratégie', 'استراتيجية', '/ʃtʁateˈɡiː/', ARRAY['Plan', 'Konzept', 'Vorgehen'], ARRAY['Chaos', 'Planlosigkeit'], ARRAY['strategisch', 'Stratege', 'strategieren'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business']),
  (gen_random_uuid(), 'Investition', 'investment', 'die', 'die Investitionen', 'Diese Investition in moderne Technologie hat sich bereits nach einem Jahr amortisiert. — This investment in modern technology paid for itself within a year.', 'B2', 'business', 'Professional & Business', 'investissement', 'استثمار', '/ɪnvɛstiˈt͡si̯oːn/', ARRAY['Anlage', 'Kapitalanlage', 'Einlage'], ARRAY['Desinvestition', 'Rückzug'], ARRAY['investieren', 'Investor', 'investiv'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business', 'finance']),
  (gen_random_uuid(), 'Konkurrenz', 'competition', 'die', 'die Konkurrenzen', 'Die Konkurrenz in der Branche ist in den letzten Jahren deutlich härter geworden. — The competition in the industry has become much tougher in recent years.', 'B2', 'business', 'Professional & Business', 'concurrence', 'منافسة', '/kɔnkʊˈʁɛnt͡s/', ARRAY['Wettbewerb', 'Rivalität', 'Mitbewerb'], ARRAY['Monopol', 'Alleinstellung'], ARRAY['konkurrieren', 'Konkurrent', 'konkurrenzfähig'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business']),
  (gen_random_uuid(), 'Gewinn', 'profit', 'der', 'die Gewinne', 'Der Gewinn des Unternehmens ist im dritten Quartal um fünfzehn Prozent gestiegen. — The company''s profit rose by fifteen percent in the third quarter.', 'B2', 'business', 'Professional & Business', 'bénéfice', 'ربح', '/ɡəˈvɪn/', ARRAY['Ertrag', 'Profit', 'Überschuss'], ARRAY['Verlust', 'Defizit', 'Minus'], ARRAY['gewinnen', 'Gewinner', 'gewinnbringend'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business', 'finance']),
  (gen_random_uuid(), 'Umsatz', 'revenue', 'der', 'die Umsätze', 'Der jährliche Umsatz liegt bei über einer Million Euro. — The annual revenue is over one million euros.', 'B2', 'business', 'Professional & Business', 'chiffre d''affaires', 'إيرادات', '/ˈʊmzat͡s/', ARRAY['Einnahmen', 'Erlös', 'Ertrag'], ARRAY['Ausgaben', 'Kosten'], ARRAY['umsetzen', 'Umsatzsteuer', 'umsatzstark'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business', 'finance']),
  (gen_random_uuid(), 'Bilanz', 'balance sheet', 'die', 'die Bilanzen', 'Die Bilanz des Unternehmens weist ein gesundes Eigenkapital aus. — The company''s balance sheet shows a healthy equity ratio.', 'B2', 'business', 'Professional & Business', 'bilan', 'ميزانية عمومية', '/biˈlant͡s/', ARRAY['Jahresabschluss', 'Rechnungslegung'], NULL, ARRAY['bilanzieren', 'Bilanzierung', 'Bilanzsumme'], NULL, 'common', 4, 'noun', ARRAY['B2', 'business', 'finance']),
  (gen_random_uuid(), 'Führungskraft', 'executive', 'die', 'die Führungskräfte', 'Die Führungskräfte des Unternehmens nehmen an einem mehrtägigen Seminar teil. — The company''s executives are attending a multi-day seminar.', 'B2', 'business', 'Professional & Business', 'cadre dirigeant', 'كفاءة قيادية', '/ˈfyːʁʊŋsˌkʁaft/', ARRAY['Manager', 'Leitungskraft', 'Vorgesetzter'], ARRAY['Mitarbeiter', 'Untergebener'], ARRAY['führen', 'Führung', 'Führungsstil'], NULL, 'common', 4, 'noun', ARRAY['B2', 'business', 'management']),
  (gen_random_uuid(), 'Niederlassung', 'branch', 'die', 'die Niederlassungen', 'Die Firma eröffnet eine neue Niederlassung in München. — The company is opening a new branch in Munich.', 'B2', 'business', 'Professional & Business', 'succursale', 'فرع', '/ˈniːdɐˌlasʊŋ/', ARRAY['Filiale', 'Dependance', 'Zweigstelle'], ARRAY['Hauptsitz', 'Zentrale'], ARRAY['niederlassen', 'Niederlassungsleiter'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business']),
  (gen_random_uuid(), 'Vertrieb', 'sales/distribution', 'der', NULL, 'Er arbeitet im Vertrieb und ist für den asiatischen Markt zuständig. — He works in sales and is responsible for the Asian market.', 'B2', 'business', 'Professional & Business', 'distribution/vente', 'توزيع ومبيعات', '/fɛɐˈtʁiːp/', ARRAY['Verkauf', 'Absatz', 'Distribution'], NULL, ARRAY['vertreiben', 'Vertriebler', 'Vertriebsweg'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business']),
  (gen_random_uuid(), 'Personal', 'staff', 'das', NULL, 'Das Personal wurde über die neuen Regelungen informiert. — The staff has been informed about the new regulations.', 'B2', 'business', 'Professional & Business', 'personnel', 'موظفون', '/pɛʁzoˈnaːl/', ARRAY['Belegschaft', 'Mitarbeiter', 'Team'], ARRAY['Führung', 'Leitung'], ARRAY['personell', 'Personalabteilung', 'Personalchef'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business', 'HR']),
  (gen_random_uuid(), 'Zusammenarbeit', 'collaboration', 'die', NULL, 'Die Zusammenarbeit zwischen den beiden Abteilungen funktioniert hervorragend. — The collaboration between the two departments works excellently.', 'B2', 'business', 'Professional & Business', 'collaboration', 'تعاون', '/t͡suˈzamənˌʔaʁbaɪ̯t/', ARRAY['Kooperation', 'Teamwork', 'Partnerschaft'], ARRAY['Konkurrenz', 'Gegnerschaft'], ARRAY['zusammenarbeiten', 'kooperieren', 'Arbeitsgemeinschaft'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business', 'soft-skills']),
  (gen_random_uuid(), 'Auftrag', 'order/contract', 'der', 'die Aufträge', 'Der Auftrag muss bis Ende der Woche abgeschlossen sein. — The order must be completed by the end of the week.', 'B2', 'business', 'Professional & Business', 'commande/mandat', 'طلب/عقد', '/ˈaʊ̯ftʁaːk/', ARRAY['Bestellung', 'Order', 'Anweisung'], ARRAY['Stornierung', 'Absage'], ARRAY['beauftragen', 'Auftraggeber', 'Auftragnehmer'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business']),
  (gen_random_uuid(), 'Kündigung', 'termination/resignation', 'die', 'die Kündigungen', 'Seine Kündigung hat alle überrascht, da er erst befördert worden war. — His resignation surprised everyone since he had just been promoted.', 'B2', 'business', 'Professional & Business', 'licenciement/démission', 'إنهاء خدمة/استقالة', '/ˈkʏndɪɡʊŋ/', ARRAY['Entlassung', 'Austritt', 'Rücktritt'], ARRAY['Einstellung', 'Anstellung', 'Beförderung'], ARRAY['kündigen', 'Kündigungsfrist', 'Kündigungsschutz'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business', 'HR']),
  (gen_random_uuid(), 'Gehaltsverhandlung', 'salary negotiation', 'die', 'die Gehaltsverhandlungen', 'Die Gehaltsverhandlungen mit dem Betriebsrat ziehen sich bereits seit Wochen hin. — The salary negotiations with the works council have been dragging on for weeks.', 'B2', 'business', 'Professional & Business', 'négociation salariale', 'تفاوض على الراتب', '/ɡəˈhalt͡sfɛɐˌhandlʊŋ/', ARRAY['Lohnverhandlung', 'Tarifverhandlung'], NULL, ARRAY['Gehalt', 'verhandeln', 'Gehaltserhöhung'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'business', 'career']),
  (gen_random_uuid(), 'Geschäftsführer', 'managing director', 'der', 'die Geschäftsführer', 'Der Geschäftsführer hat die Verantwortung für das gesamte Unternehmen. — The managing director is responsible for the entire company.', 'B2', 'business', 'Professional & Business', 'directeur général', 'مدير تنفيذي', '/ɡəˈʃɛft͡sˌfyːʁɐ/', ARRAY['CEO', 'Vorstand', 'Direktor'], ARRAY['Angestellter', 'Mitarbeiter'], ARRAY['Geschäft', 'führen', 'Geschäftsführung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business', 'management']),
  (gen_random_uuid(), 'Abteilung', 'department', 'die', 'die Abteilungen', 'In unserer Abteilung arbeiten zwölf Kollegen aus vier verschiedenen Ländern. — Twelve colleagues from four different countries work in our department.', 'B2', 'business', 'Professional & Business', 'département/service', 'قسم', '/apˈtaɪ̯lʊŋ/', ARRAY['Bereich', 'Ressort', 'Sektion'], NULL, ARRAY['abteilen', 'Abteilungsleiter', 'Abteilungsversammlung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business']),
  (gen_random_uuid(), 'Besprechung', 'meeting', 'die', 'die Besprechungen', 'Die wöchentliche Besprechung findet immer montags um neun Uhr statt. — The weekly meeting always takes place on Mondays at nine o''clock.', 'B2', 'business', 'Professional & Business', 'réunion', 'اجتماع', '/bəˈʃpʁɛçʊŋ/', ARRAY['Meeting', 'Sitzung', 'Konferenz'], NULL, ARRAY['besprechen', 'Besprechungsraum', 'besprechbar'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business']),
  (gen_random_uuid(), 'Standort', 'location', 'der', 'die Standorte', 'Der neue Standort bietet bessere Verkehrsanbindungen für die Mitarbeiter. — The new location offers better transport connections for employees.', 'B2', 'business', 'Professional & Business', 'site/emplacement', 'موقع', '/ˈʃtantˌʔɔʁt/', ARRAY['Ort', 'Platz', 'Position'], NULL, ARRAY['Standortvorteil', 'standortbezogen', 'Unternehmensstandort'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business']),
  (gen_random_uuid(), 'Ausschreibung', 'tender', 'die', 'die Ausschreibungen', 'Die Ausschreibung für das Bauprojekt läuft noch bis Ende des Monats. — The tender for the construction project is still open until the end of the month.', 'B2', 'business', 'Professional & Business', 'appel d''offres', 'مناقصة', '/ˈaʊ̯sˌʃʁaɪ̯bʊŋ/', ARRAY['Submission', 'Angebotsaufforderung'], NULL, ARRAY['ausschreiben', 'Ausschreibungsfrist', 'ausschreibend'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'business', 'procurement']),
  (gen_random_uuid(), 'Lieferant', 'supplier', 'der', 'die Lieferanten', 'Wir suchen einen zuverlässigen Lieferanten für Rohstoffe aus der Region. — We are looking for a reliable supplier for raw materials from the region.', 'B2', 'business', 'Professional & Business', 'fournisseur', 'مورد', '/liːfəˈʁant/', ARRAY['Zulieferer', 'Anbieter', 'Vendor'], ARRAY['Abnehmer', 'Kunde'], ARRAY['liefern', 'Lieferung', 'Lieferkette'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business', 'logistics']),
  (gen_random_uuid(), 'Produktivität', 'productivity', 'die', NULL, 'Die Produktivität konnte durch die neuen Arbeitsabläufe erheblich gesteigert werden. — Productivity was significantly increased through the new workflows.', 'B2', 'business', 'Professional & Business', 'productivité', 'إنتاجية', '/pʁodʊktiviˈtɛːt/', ARRAY['Leistung', 'Effizienz', 'Leistungsfähigkeit'], ARRAY['Ineffizienz', 'Stillstand'], ARRAY['produktiv', 'produzieren', 'Produktionssteigerung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business']),
  (gen_random_uuid(), 'Zielsetzung', 'goal setting', 'die', 'die Zielsetzungen', 'Eine klare Zielsetzung ist der erste Schritt zum Erfolg. — A clear goal setting is the first step to success.', 'B2', 'business', 'Professional & Business', 'définition d''objectifs', 'تحديد هدف', '/ˈt͡siːlˌzɛt͡sʊŋ/', ARRAY['Zielvorgabe', 'Zieldefinition', 'Vorsatz'], ARRAY['Ziellosigkeit', 'Planlosigkeit'], ARRAY['Ziel', 'setzen', 'zielgerichtet'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business', 'management']),
  (gen_random_uuid(), 'Budget', 'budget', 'das', 'die Budgets', 'Das Budget für die Marketingabteilung wurde für dieses Jahr aufgestockt. — The budget for the marketing department was increased this year.', 'B2', 'business', 'Professional & Business', 'budget', 'ميزانية', '/bʏˈd͡ʒeː/', ARRAY['Etat', 'Finanzrahmen', 'Mittel'], ARRAY['Überschreitung', 'Defizit'], ARRAY['budgetieren', 'Budgetplanung', 'Budgetkürzung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business', 'finance']),
  (gen_random_uuid(), 'Marktanalyse', 'market analysis', 'die', 'die Marktanalysen', 'Laut der aktuellen Marktanalyse steigt die Nachfrage nach nachhaltigen Produkten. — According to the current market analysis, demand for sustainable products is rising.', 'B2', 'business', 'Professional & Business', 'analyse de marché', 'تحليل سوق', '/ˈmaʁktʔanaˌlyːzə/', ARRAY['Marktforschung', 'Marktstudie', 'Markterhebung'], NULL, ARRAY['Markt', 'analysieren', 'Marktanalyst'], NULL, 'common', 4, 'noun', ARRAY['B2', 'business', 'marketing']),
  (gen_random_uuid(), 'Geschäftsbericht', 'annual report', 'der', 'die Geschäftsberichte', 'Der Geschäftsbericht wird allen Aktionären zugeschickt. — The annual report is sent to all shareholders.', 'B2', 'business', 'Professional & Business', 'rapport d''activité', 'تقرير أعمال', '/ɡəˈʃɛft͡sbəˌʁɪçt/', ARRAY['Jahresbericht', 'Rechenschaftsbericht'], NULL, ARRAY['Geschäft', 'berichten', 'Bericht'], NULL, 'rare', 3, 'noun', ARRAY['B2', 'business', 'finance']),
  (gen_random_uuid(), 'Fusion', 'merger', 'die', 'die Fusionen', 'Die Fusion der beiden Banken hat zu einem der größten Finanzinstitute Europas geführt. — The merger of the two banks has created one of the largest financial institutions in Europe.', 'B2', 'business', 'Professional & Business', 'fusion', 'اندماج', '/fuˈzi̯oːn/', ARRAY['Zusammenschluss', 'Vereinigung', 'Integration'], ARRAY['Trennung', 'Spaltung', 'Übernahme'], ARRAY['fusionieren', 'Fusionsprozess', 'Fusionspartner'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'business', 'corporate']),
  (gen_random_uuid(), 'Wettbewerb', 'competition', 'der', 'die Wettbewerbe', 'Im globalen Wettbewerb müssen deutsche Unternehmen innovativ bleiben. — In global competition, German companies must remain innovative.', 'B2', 'business', 'Professional & Business', 'compétition', 'منافسة', '/ˈvɛtbəˌvɛʁp/', ARRAY['Konkurrenz', 'Rivalität', 'Wettkampf'], ARRAY['Kooperation', 'Monopol'], ARRAY['wetteifern', 'wettbewerbsfähig', 'Wettbewerber'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business', 'economics']),
  (gen_random_uuid(), 'Unternehmen', 'company/enterprise', 'das', 'die Unternehmen', 'Das Unternehmen beschäftigt weltweit über zehntausend Mitarbeiter. — The company employs over ten thousand people worldwide.', 'B2', 'business', 'Professional & Business', 'entreprise', 'شركة/مؤسسة', '/ʊntɐˈneːmən/', ARRAY['Firma', 'Betrieb', 'Konzern'], NULL, ARRAY['unternehmen', 'Unternehmer', 'unternehmerisch'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business']),
  (gen_random_uuid(), 'Verhandlung', 'negotiation', 'die', 'die Verhandlungen', 'Die Verhandlung über den neuen Tarifvertrag war äußerst schwierig. — The negotiation over the new collective agreement was extremely difficult.', 'B2', 'business', 'Professional & Business', 'négociation', 'تفاوض', '/fɛɐˈhandlʊŋ/', ARRAY['Gespräch', 'Unterhandlung', 'Aussprache'], ARRAY['Abbruch', 'Streik'], ARRAY['verhandeln', 'Verhandlungspartner', 'verhandelbar'], NULL, 'common', 3, 'noun', ARRAY['B2', 'business', 'law']),
  (gen_random_uuid(), 'Rentabilität', 'profitability', 'die', NULL, 'Die Rentabilität des Projekts wird vor der endgültigen Entscheidung geprüft. — The profitability of the project will be examined before the final decision.', 'B2', 'business', 'Professional & Business', 'rentabilité', 'ربحية', '/ʁɛntabiliˈtɛːt/', ARRAY['Wirtschaftlichkeit', 'Ertragskraft', 'Profitabilität'], ARRAY['Unwirtschaftlichkeit', 'Verlust'], ARRAY['rentabel', 'Rente', 'rentieren'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'business', 'finance']);
INSERT INTO public.vocabulary (id, german_word, english_translation, article, plural, example_sentence, level, category, theme, french_translation, arabic_translation, ipa, synonyms, antonyms, word_family, verb_forms, frequency, difficulty_score, word_type, tags) VALUES
  (gen_random_uuid(), 'These', 'thesis', 'die', 'die Thesen', 'Der Professor verteidigte seine These mit überzeugenden Argumenten. — The professor defended his thesis with convincing arguments.', 'B2', 'academic', 'Academic & Research', 'thèse', 'أطروحة', '/ˈteːzə/', ARRAY['Behauptung', 'Hypothese', 'Annahme'], ARRAY['Fakt', 'Gewissheit'], ARRAY['thesenhaft', 'Thesenpapier', 'thetisch'], NULL, 'common', 4, 'noun', ARRAY['B2', 'academic', 'science']),
  (gen_random_uuid(), 'Analyse', 'analysis', 'die', 'die Analysen', 'Die Analyse der Daten hat interessante Muster ergeben. — The analysis of the data revealed interesting patterns.', 'B2', 'academic', 'Academic & Research', 'analyse', 'تحليل', '/anaˈlyːzə/', ARRAY['Untersuchung', 'Auswertung', 'Studie'], ARRAY['Synthese', 'Zusammenfassung'], ARRAY['analysieren', 'Analytiker', 'analytisch'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic']),
  (gen_random_uuid(), 'Methodik', 'methodology', 'die', 'die Methodiken', 'Die Methodik der Studie wurde von mehreren Experten überprüft. — The methodology of the study was reviewed by several experts.', 'B2', 'academic', 'Academic & Research', 'méthodologie', 'منهجية', '/meˈtoːdɪk/', ARRAY['Methodologie', 'Vorgehensweise', 'Methode'], NULL, ARRAY['Methode', 'methodisch', 'Methodiker'], NULL, 'common', 4, 'noun', ARRAY['B2', 'academic', 'research']),
  (gen_random_uuid(), 'Forschung', 'research', 'die', 'die Forschungen', 'Die Forschung auf dem Gebiet der künstlichen Intelligenz macht rasche Fortschritte. — Research in the field of artificial intelligence is making rapid progress.', 'B2', 'academic', 'Academic & Research', 'recherche', 'بحث', '/ˈfɔʁʃʊŋ/', ARRAY['Wissenschaft', 'Studium', 'Erforschung'], NULL, ARRAY['forschen', 'Forscher', 'Forschungsergebnis'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic']),
  (gen_random_uuid(), 'Hypothese', 'hypothesis', 'die', 'die Hypothesen', 'Die Hypothese konnte durch das Experiment nicht bestätigt werden. — The hypothesis could not be confirmed by the experiment.', 'B2', 'academic', 'Academic & Research', 'hypothèse', 'فرضية', '/hypoˈteːzə/', ARRAY['Annahme', 'Vermutung', 'These'], ARRAY['Gewissheit', 'Tatsache'], ARRAY['hypothetisch', 'Hypothesentest'], NULL, 'common', 4, 'noun', ARRAY['B2', 'academic', 'science']),
  (gen_random_uuid(), 'Studiengang', 'course of study', 'der', 'die Studiengänge', 'Dieser Studiengang verbindet Wirtschaftswissenschaften mit Informatik. — This course of study combines economics with computer science.', 'B2', 'academic', 'Academic & Research', 'filière universitaire', 'مسار دراسي', '/ˈʃtuːdi̯ənˌɡaŋ/', ARRAY['Studienfach', 'Fachrichtung', 'Studium'], NULL, ARRAY['studieren', 'Student', 'Studienberatung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic', 'education']),
  (gen_random_uuid(), 'Seminar', 'seminar', 'das', 'die Seminare', 'Im Seminar wurden aktuelle Forschungsergebnisse diskutiert. — Current research findings were discussed in the seminar.', 'B2', 'academic', 'Academic & Research', 'séminaire', 'ندوة', '/zemiˈnaːɐ̯/', ARRAY['Kurs', 'Workshop', 'Lehrveranstaltung'], NULL, ARRAY['Seminararbeit', 'Seminarteilnehmer', 'Seminarraum'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic', 'education']),
  (gen_random_uuid(), 'Vorlesung', 'lecture', 'die', 'die Vorlesungen', 'Die Vorlesung über Quantenphysik findet im Hörsaal statt. — The lecture on quantum physics takes place in the lecture hall.', 'B2', 'academic', 'Academic & Research', 'cours magistral', 'محاضرة', '/ˈfoːɐ̯leːzʊŋ/', ARRAY['Vortrag', 'Lehrvortrag', 'Präsentation'], NULL, ARRAY['vorlesen', 'Vorlesungsreihe', 'Vorlesungszeit'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic', 'education']),
  (gen_random_uuid(), 'Publikation', 'publication', 'die', 'die Publikationen', 'Seine neueste Publikation wurde in einer renommierten Fachzeitschrift veröffentlicht. — His latest publication was published in a renowned journal.', 'B2', 'academic', 'Academic & Research', 'publication', 'منشور', '/publikaˈt͡si̯oːn/', ARRAY['Veröffentlichung', 'Schrift', 'Aufsatz'], NULL, ARRAY['publizieren', 'Publikum', 'Publikationsorgan'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic']),
  (gen_random_uuid(), 'Fachzeitschrift', 'journal', 'die', 'die Fachzeitschriften', 'In dieser Fachzeitschrift erscheinen monatlich neue Artikel aus der Medizinforschung. — New articles from medical research appear monthly in this journal.', 'B2', 'academic', 'Academic & Research', 'revue spécialisée', 'مجلة متخصصة', '/ˈfaxˌt͡saɪ̯tʃʁɪft/', ARRAY['Journal', 'Fachblatt', 'Wissenschaftszeitschrift'], NULL, ARRAY['Fach', 'Zeitschrift', 'Fachbereich'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic', 'publishing']),
  (gen_random_uuid(), 'Quelle', 'source', 'die', 'die Quellen', 'Der Wissenschaftler gab alle Quellen in seinem Literaturverzeichnis an. — The scientist listed all sources in his bibliography.', 'B2', 'academic', 'Academic & Research', 'source', 'مصدر', '/ˈkvɛlə/', ARRAY['Nachweis', 'Referenz', 'Ursprung'], NULL, ARRAY['quellen', 'Quellenangabe', 'Quellenverzeichnis'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic', 'research']),
  (gen_random_uuid(), 'Studie', 'study', 'die', 'die Studien', 'Eine aktuelle Studie belegt den Zusammenhang zwischen Bewegung und kognitiver Leistung. — A recent study proves the connection between exercise and cognitive performance.', 'B2', 'academic', 'Academic & Research', 'étude', 'دراسة', '/ˈʃtuːdi̯ə/', ARRAY['Untersuchung', 'Forschung', 'Erhebung'], NULL, ARRAY['studieren', 'Studiengebühren', 'Studienplatz'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic']),
  (gen_random_uuid(), 'Stipendium', 'scholarship', 'das', 'die Stipendien', 'Sie hat ein Stipendium für ihr Masterstudium in Berlin erhalten. — She received a scholarship for her master''s degree in Berlin.', 'B2', 'academic', 'Academic & Research', 'bourse d''études', 'منحة دراسية', '/ʃtiˈpɛndi̯ʊm/', ARRAY['Förderung', 'Unterstützung', 'Begabtenförderung'], NULL, ARRAY['Stipendiat', 'Stipendienprogramm', 'Stipendiengeber'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic', 'finance']),
  (gen_random_uuid(), 'Fachbereich', 'department/field', 'der', 'die Fachbereiche', 'Der Fachbereich Physik gehört zur naturwissenschaftlichen Fakultät. — The physics department belongs to the faculty of natural sciences.', 'B2', 'academic', 'Academic & Research', 'département/domaine', 'قسم أكاديمي', '/ˈfaxbəˌʁaɪ̯ç/', ARRAY['Fakultät', 'Disziplin', 'Fachgebiet'], NULL, ARRAY['Fach', 'Bereich', 'fachbereichsübergreifend'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic', 'education']),
  (gen_random_uuid(), 'Auswertung', 'evaluation', 'die', 'die Auswertungen', 'Die Auswertung der Umfrageergebnisse dauert noch an. — The evaluation of the survey results is still ongoing.', 'B2', 'academic', 'Academic & Research', 'évaluation/exploitation', 'تقييم/تحليل', '/ˈaʊ̯sveːɐ̯tʊŋ/', ARRAY['Evaluierung', 'Analyse', 'Bewertung'], NULL, ARRAY['auswerten', 'Wert', 'Auswertungsmethode'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic']),
  (gen_random_uuid(), 'Forschungsergebnis', 'research finding', 'das', 'die Forschungsergebnisse', 'Die Forschungsergebnisse wurden auf einer internationalen Konferenz präsentiert. — The research findings were presented at an international conference.', 'B2', 'academic', 'Academic & Research', 'résultat de recherche', 'نتيجة بحثية', '/ˈfɔʁʃʊŋsʔɛɐˌɡeːpnɪs/', ARRAY['Erkenntnis', 'Resultat', 'Untersuchungsergebnis'], NULL, ARRAY['Forschung', 'Ergebnis', 'Forschungsarbeit'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic']),
  (gen_random_uuid(), 'Erkenntnis', 'insight/finding', 'die', 'die Erkenntnisse', 'Die wissenschaftliche Erkenntnis hat zu einem Paradigmenwechsel geführt. — The scientific insight led to a paradigm shift.', 'B2', 'academic', 'Academic & Research', 'connaissance/découverte', 'معرفة/اكتشاف', '/ɛɐˈkɛntnɪs/', ARRAY['Einsicht', 'Feststellung', 'Wissen'], ARRAY['Unwissenheit', 'Ignoranz'], ARRAY['erkennen', 'erkenntlich', 'Erkenntnistheorie'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic']),
  (gen_random_uuid(), 'Disziplin', 'discipline', 'die', 'die Disziplinen', 'In dieser wissenschaftlichen Disziplin werden neue Forschungsmethoden entwickelt. — In this scientific discipline, new research methods are being developed.', 'B2', 'academic', 'Academic & Research', 'discipline', 'تخصص', '/dɪst͡siˈpliːn/', ARRAY['Fach', 'Fachrichtung', 'Wissenschaftszweig'], NULL, ARRAY['disziplinär', 'disziplinieren', 'Interdisziplinarität'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic']),
  (gen_random_uuid(), 'Semester', 'semester', 'das', 'die Semester', 'Im nächsten Semester werde ich ein Auslandssemester in Frankreich verbringen. — Next semester I will spend a semester abroad in France.', 'B2', 'academic', 'Academic & Research', 'semestre', 'فصل دراسي', '/zeˈmɛstɐ/', ARRAY['Studienhalbjahr', 'Halbjahr'], NULL, ARRAY['Semesterbeitrag', 'Semesterferien', 'Semesterstart'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic', 'education']),
  (gen_random_uuid(), 'Referat', 'presentation', 'das', 'die Referate', 'Für das Referat habe ich mich mit dem Thema Klimawandel beschäftigt. — For the presentation I dealt with the topic of climate change.', 'B2', 'academic', 'Academic & Research', 'exposé', 'تقرير/عرض', '/ʁefeˈʁaːt/', ARRAY['Vortrag', 'Präsentation', 'Ausarbeitung'], NULL, ARRAY['referieren', 'Referent', 'Referatsgruppe'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic']),
  (gen_random_uuid(), 'Nachweis', 'proof/evidence', 'der', 'die Nachweise', 'Der Nachweis der Wirksamkeit des Medikaments wurde durch klinische Studien erbracht. — Proof of the drug''s effectiveness was provided through clinical trials.', 'B2', 'academic', 'Academic & Research', 'preuve/justification', 'إثبات', '/ˈnaːxvaɪ̯s/', ARRAY['Beweis', 'Beleg', 'Bestätigung'], ARRAY['Widerlegung', 'Anfechtung'], ARRAY['nachweisen', 'nachweisbar', 'Nachweispflicht'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic', 'science']),
  (gen_random_uuid(), 'Proseminar', 'proseminar', 'das', 'die Proseminare', 'Das Proseminar dient der Einführung in wissenschaftliches Arbeiten. — The proseminar serves as an introduction to academic work.', 'B2', 'academic', 'Academic & Research', 'proséminaire', 'ندوة تمهيدية', '/ˈpʁoːzemiˌnaːɐ̯/', ARRAY['Einführungsseminar', 'Grundkurs'], ARRAY['Oberseminar', 'Hauptseminar'], ARRAY['Seminar', 'Pro-'], NULL, 'rare', 3, 'noun', ARRAY['B2', 'academic']),
  (gen_random_uuid(), 'Abschlussarbeit', 'final thesis', 'die', 'die Abschlussarbeiten', 'Für meine Abschlussarbeit untersuche ich die Auswirkungen von Social Media auf Jugendliche. — For my final thesis I am examining the effects of social media on adolescents.', 'B2', 'academic', 'Academic & Research', 'mémoire de fin d''études', 'رسالة تخرج', '/ˈapʃlʊsʔaʁˌbaɪ̯t/', ARRAY['Bachelorarbeit', 'Masterarbeit', 'Dissertation'], NULL, ARRAY['Abschluss', 'Arbeit', 'abschließen'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic']),
  (gen_random_uuid(), 'Plagiat', 'plagiarism', 'das', 'die Plagiate', 'Ein Plagiat kann zum Ausschluss vom Studium führen. — Plagiarism can lead to exclusion from the study program.', 'B2', 'academic', 'Academic & Research', 'plagiat', 'انتحال أكاديمي', '/plaˈɡi̯aːt/', ARRAY['Ideenklau', 'Geistiger Diebstahl', 'Urheberrechtsverletzung'], ARRAY['Originalität', 'Eigenleistung'], ARRAY['plagiieren', 'Plagiatsvorwurf', 'Plagiatsprüfung'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'academic', 'ethics']),
  (gen_random_uuid(), 'Bibliothek', 'library', 'die', 'die Bibliotheken', 'Die Universitätsbibliothek hat bis Mitternacht geöffnet. — The university library is open until midnight.', 'B2', 'academic', 'Academic & Research', 'bibliothèque', 'مكتبة', '/biblioˈteːk/', ARRAY['Bücherei', 'Mediathek', 'Archiv'], NULL, ARRAY['bibliothekarisch', 'Bibliothekar', 'Bibliothekskatalog'], NULL, 'common', 3, 'noun', ARRAY['B2', 'academic']);
INSERT INTO public.vocabulary (id, german_word, english_translation, article, plural, example_sentence, level, category, theme, french_translation, arabic_translation, ipa, synonyms, antonyms, word_family, verb_forms, frequency, difficulty_score, word_type, tags) VALUES
  (gen_random_uuid(), 'Globalisierung', 'globalization', 'die', NULL, 'Die Globalisierung hat den internationalen Handel enorm beschleunigt. — Globalization has enormously accelerated international trade.', 'B2', 'society', 'Society & Global Issues', 'mondialisation', 'عولمة', '/ɡlobaliˈziːʁʊŋ/', ARRAY['Internationalisierung', 'Weltvernetzung'], ARRAY['Regionalisierung', 'Isolation'], ARRAY['global', 'globalisieren', 'Globalisierungsgegner'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society', 'economics']),
  (gen_random_uuid(), 'Integration', 'integration', 'die', 'die Integrationen', 'Die Integration von Migranten in den Arbeitsmarkt ist eine zentrale gesellschaftliche Aufgabe. — The integration of migrants into the labor market is a central societal task.', 'B2', 'society', 'Society & Global Issues', 'intégration', 'اندماج', '/ɪnteɡʁaˈt͡si̯oːn/', ARRAY['Eingliederung', 'Eingewöhnung', 'Assimilation'], ARRAY['Ausgrenzung', 'Segregation', 'Isolation'], ARRAY['integrieren', 'integrativ', 'Integrationskurs'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Migration', 'migration', 'die', 'die Migrationen', 'Die Migration aus wirtschaftlichen Gründen hat in den letzten Jahrzehnten zugenommen. — Migration for economic reasons has increased in recent decades.', 'B2', 'society', 'Society & Global Issues', 'migration', 'هجرة', '/miɡʁaˈt͡si̯oːn/', ARRAY['Zuwanderung', 'Einwanderung', 'Auswanderung'], ARRAY['Bleiben', 'Verbleib'], ARRAY['migrieren', 'Migrant', 'Migrationshintergrund'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Bevölkerung', 'population', 'die', 'die Bevölkerungen', 'Die Bevölkerung Deutschlands ist in den letzten Jahren leicht gewachsen. — Germany''s population has grown slightly in recent years.', 'B2', 'society', 'Society & Global Issues', 'population', 'سكان', '/bəˈfœlkəʁʊŋ/', ARRAY['Einwohner', 'Bewohner', 'Volk'], NULL, ARRAY['bevölkern', 'bevölkerungsreich', 'Bevölkerungsdichte'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Wohlstand', 'prosperity', 'der', NULL, 'Der wirtschaftliche Wohlstand hat zu einer höheren Lebenserwartung geführt. — Economic prosperity has led to a higher life expectancy.', 'B2', 'society', 'Society & Global Issues', 'prospérité', 'ازدهار', '/ˈvoːlʃtant/', ARRAY['Reichtum', 'Überfluss', 'Wohlhabenheit'], ARRAY['Armut', 'Not', 'Mangel'], ARRAY['wohlhabend', 'Wohlstandsgesellschaft', 'Wohlstandsgefälle'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society', 'economics']),
  (gen_random_uuid(), 'Ungleichheit', 'inequality', 'die', 'die Ungleichheiten', 'Die soziale Ungleichheit in der Gesellschaft nimmt stetig zu. — Social inequality in society is steadily increasing.', 'B2', 'society', 'Society & Global Issues', 'inégalité', 'لا مساواة', '/ˈʊnɡlaɪ̯çhaɪ̯t/', ARRAY['Ungerechtigkeit', 'Disparität', 'Gefälle'], ARRAY['Gleichheit', 'Gleichberechtigung', 'Gerechtigkeit'], ARRAY['ungleich', 'Gleichheit', 'Ungleichbehandlung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Armut', 'poverty', 'die', NULL, 'In vielen Regionen der Welt herrscht extreme Armut. — Extreme poverty prevails in many regions of the world.', 'B2', 'society', 'Society & Global Issues', 'pauvreté', 'فقر', '/ˈaʁmuːt/', ARRAY['Not', 'Mittellosigkeit', 'Bedürftigkeit'], ARRAY['Reichtum', 'Wohlstand', 'Überfluss'], ARRAY['arm', 'Armutsgrenze', 'Armutsbekämpfung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Bildungssystem', 'education system', 'das', 'die Bildungssysteme', 'Das deutsche Bildungssystem unterscheidet sich stark von dem in anderen Ländern. — The German education system differs greatly from those in other countries.', 'B2', 'society', 'Society & Global Issues', 'système éducatif', 'نظام تعليمي', '/ˈbɪldʊŋszʏsˌteːm/', ARRAY['Schulsystem', 'Bildungswesen', 'Erziehungssystem'], NULL, ARRAY['Bildung', 'System', 'Bildungsreform'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society', 'education']),
  (gen_random_uuid(), 'Chancengleichheit', 'equal opportunity', 'die', NULL, 'Chancengleichheit im Bildungswesen ist ein wichtiges gesellschaftliches Ziel. — Equal opportunity in education is an important societal goal.', 'B2', 'society', 'Society & Global Issues', 'égalité des chances', 'تكافؤ فرص', '/ˈtʃansn̩ˌɡlaɪ̯çhaɪ̯t/', ARRAY['Gleichberechtigung', 'Gerechtigkeit', 'Fairness'], ARRAY['Diskriminierung', 'Ungerechtigkeit'], ARRAY['Chance', 'gleich', 'Chancengerechtigkeit'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Diskriminierung', 'discrimination', 'die', 'die Diskriminierungen', 'Diskriminierung aufgrund der Herkunft ist in Deutschland gesetzlich verboten. — Discrimination based on origin is prohibited by law in Germany.', 'B2', 'society', 'Society & Global Issues', 'discrimination', 'تمييز', '/dɪskʁɪmiˈniːʁʊŋ/', ARRAY['Benachteiligung', 'Ungleichbehandlung', 'Ausgrenzung'], ARRAY['Gleichbehandlung', 'Toleranz', 'Akzeptanz'], ARRAY['diskriminieren', 'diskriminierend', 'Antidiskriminierung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Vorurteil', 'prejudice', 'das', 'die Vorurteile', 'Vorurteile gegenüber anderen Kulturen entstehen oft aus Unwissenheit. — Prejudices towards other cultures often arise from ignorance.', 'B2', 'society', 'Society & Global Issues', 'préjugé', 'تحيز مسبق', '/ˈfoːɐ̯ʔʊʁˌtaɪ̯l/', ARRAY['Klischee', 'Stereotyp', 'Voreingenommenheit'], ARRAY['Aufgeschlossenheit', 'Toleranz', 'Objektivität'], ARRAY['vorurteilsfrei', 'vorurteilsbelastet', 'Urteil'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Gesellschaft', 'society', 'die', 'die Gesellschaften', 'Unsere Gesellschaft wird zunehmend multikultureller. — Our society is becoming increasingly multicultural.', 'B2', 'society', 'Society & Global Issues', 'société', 'مجتمع', '/ɡəˈzɛlʃaft/', ARRAY['Gemeinschaft', 'Sozietät', 'Gemeinwesen'], NULL, ARRAY['gesellschaftlich', 'Gesellschaftsform', 'Bürgergesellschaft'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Rassismus', 'racism', 'der', NULL, 'Rassismus hat in einer demokratischen Gesellschaft keinen Platz. — Racism has no place in a democratic society.', 'B2', 'society', 'Society & Global Issues', 'racisme', 'عنصرية', '/ʁaˈsɪsmʊs/', ARRAY['Fremdenfeindlichkeit', 'Ausländerfeindlichkeit', 'Rassendiskriminierung'], ARRAY['Toleranz', 'Weltoffenheit', 'Antirassismus'], ARRAY['rassistisch', 'Rassist', 'antirassistisch'], NULL, 'common', 4, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Toleranz', 'tolerance', 'die', NULL, 'Toleranz gegenüber anderen Lebensweisen ist eine Grundvoraussetzung für ein friedliches Zusammenleben. — Tolerance towards other ways of life is a basic requirement for peaceful coexistence.', 'B2', 'society', 'Society & Global Issues', 'tolérance', 'تسامح', '/toləˈʁant͡s/', ARRAY['Akzeptanz', 'Duldsamkeit', 'Offenheit'], ARRAY['Intoleranz', 'Fremdenfeindlichkeit', 'Engstirnigkeit'], ARRAY['tolerant', 'tolerieren', 'Toleranzgrenze'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Gerechtigkeit', 'justice', 'die', NULL, 'Soziale Gerechtigkeit ist ein zentraler Wert unserer Demokratie. — Social justice is a central value of our democracy.', 'B2', 'society', 'Society & Global Issues', 'justice', 'عدالة', '/ɡəˈʁɛçtɪçkaɪ̯t/', ARRAY['Fairness', 'Recht', 'Gleichberechtigung'], ARRAY['Ungerechtigkeit', 'Willkür', 'Parteilichkeit'], ARRAY['gerecht', 'Gerechtigkeitssinn', 'ungerecht'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society', 'law']),
  (gen_random_uuid(), 'Solidarität', 'solidarity', 'die', NULL, 'In der Krise hat sich die Solidarität in der Nachbarschaft gezeigt. — In the crisis, solidarity in the neighborhood was demonstrated.', 'B2', 'society', 'Society & Global Issues', 'solidarité', 'تضامن', '/zolidaʁiˈtɛːt/', ARRAY['Zusammenhalt', 'Verbundenheit', 'Gemeinschaftssinn'], ARRAY['Gleichgültigkeit', 'Egoismus', 'Individualismus'], ARRAY['solidarisch', 'solidarisieren', 'Solidaritätsbekundung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Vielfalt', 'diversity', 'die', NULL, 'Die kulturelle Vielfalt in unserer Stadt ist eine große Bereicherung. — The cultural diversity in our city is a great enrichment.', 'B2', 'society', 'Society & Global Issues', 'diversité', 'تنوع', '/ˈfiːlfalt/', ARRAY['Diversität', 'Multikulturalität', 'Mannigfaltigkeit'], ARRAY['Einförmigkeit', 'Uniformität', 'Gleichförmigkeit'], ARRAY['vielfältig', 'Vielfältigkeit', 'Artenvielfalt'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Religion', 'religion', 'die', 'die Religionen', 'Die Religionsfreiheit ist im Grundgesetz verankert. — Freedom of religion is enshrined in the German constitution.', 'B2', 'society', 'Society & Global Issues', 'religion', 'دين', '/ʁeliˈɡi̯oːn/', ARRAY['Glaube', 'Glaubensgemeinschaft', 'Konfession'], ARRAY['Atheismus', 'Arelligion'], ARRAY['religiös', 'Religionsgemeinschaft', 'religionsfrei'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Kultur', 'culture', 'die', 'die Kulturen', 'Die deutsche Kultur ist geprägt von einer reichen Geschichte und Tradition. — German culture is characterized by a rich history and tradition.', 'B2', 'society', 'Society & Global Issues', 'culture', 'ثقافة', '/kʊlˈtuːɐ̯/', ARRAY['Zivilisation', 'Kulturkreis', 'Brauchtum'], NULL, ARRAY['kulturell', 'Kulturlandschaft', 'Kulturprogramm'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Demografie', 'demographics', 'die', NULL, 'Der demografische Wandel stellt unser Rentensystem vor große Herausforderungen. — Demographic change poses major challenges to our pension system.', 'B2', 'society', 'Society & Global Issues', 'démographie', 'ديموغرافيا', '/demoɡʁaˈfiː/', ARRAY['Bevölkerungsentwicklung', 'Bevölkerungsstruktur', 'Bevölkerungswissenschaft'], NULL, ARRAY['demografisch', 'Demograf', 'Bevölkerungsstatistik'], NULL, 'common', 4, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Flüchtling', 'refugee', 'der', 'die Flüchtlinge', 'Viele Flüchtlinge sind auf der Suche nach Schutz vor Krieg und Verfolgung. — Many refugees are seeking protection from war and persecution.', 'B2', 'society', 'Society & Global Issues', 'réfugié', 'لاجئ', '/ˈflʏçtlɪŋ/', ARRAY['Asylsuchender', 'Asylbewerber', 'Vertriebener'], NULL, ARRAY['fliehen', 'Flucht', 'Flüchtlingslager'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Identität', 'identity', 'die', 'die Identitäten', 'Die Frage nach der eigenen Identität beschäftigt viele Menschen im Zeitalter der Globalisierung. — The question of one''s own identity preoccupies many people in the age of globalization.', 'B2', 'society', 'Society & Global Issues', 'identité', 'هوية', '/idɛntiˈtɛːt/', ARRAY['Selbstverständnis', 'Selbstbild', 'Persönlichkeit'], NULL, ARRAY['identisch', 'identifizieren', 'Identitätskrise'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Generation', 'generation', 'die', 'die Generationen', 'Die junge Generation fordert mehr Engagement beim Klimaschutz. — The young generation demands more commitment to climate protection.', 'B2', 'society', 'Society & Global Issues', 'génération', 'جيل', '/ɡeneʁaˈt͡si̯oːn/', ARRAY['Altersgruppe', 'Jahrgang', 'Generationengruppe'], NULL, ARRAY['generationell', 'Generationenkonflikt', 'Generationenvertrag'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']),
  (gen_random_uuid(), 'Minderheit', 'minority', 'die', 'die Minderheiten', 'Die Rechte von Minderheiten müssen in einer Demokratie besonders geschützt werden. — The rights of minorities must be especially protected in a democracy.', 'B2', 'society', 'Society & Global Issues', 'minorité', 'أقلية', '/ˈmɪndɐhaɪ̯t/', ARRAY['Minderheitsgruppe', 'Randgruppe'], ARRAY['Mehrheit', 'Bevölkerungsmehrheit'], ARRAY['minder', 'Minderheitenschutz', 'minderjährig'], NULL, 'common', 3, 'noun', ARRAY['B2', 'society']);
INSERT INTO public.vocabulary (id, german_word, english_translation, article, plural, example_sentence, level, category, theme, french_translation, arabic_translation, ipa, synonyms, antonyms, word_family, verb_forms, frequency, difficulty_score, word_type, tags) VALUES
  (gen_random_uuid(), 'Außenpolitik', 'foreign policy', 'die', NULL, 'Die Außenpolitik Deutschlands ist von Multilateralismus und Dialog geprägt. — Germany''s foreign policy is characterized by multilateralism and dialogue.', 'B2', 'politics', 'Politics & Diplomacy', 'politique étrangère', 'سياسة خارجية', '/ˈaʊ̯sənpolitiːk/', ARRAY['Diplomatie', 'internationale Beziehungen', 'Auswärtige Politik'], ARRAY['Innenpolitik', 'Isolationismus'], ARRAY['außenpolitisch', 'Außenminister', 'Außenpolitiker'], NULL, 'common', 4, 'noun', ARRAY['B2', 'politics']),
  (gen_random_uuid(), 'Diplomatie', 'diplomacy', 'die', NULL, 'Die Diplomatie ist das Mittel der Wahl, um internationale Konflikte friedlich zu lösen. — Diplomacy is the preferred means to resolve international conflicts peacefully.', 'B2', 'politics', 'Politics & Diplomacy', 'diplomatie', 'دبلوماسية', '/diplomaˈtiː/', ARRAY['Außenpolitik', 'Staatskunst', 'Verhandlungskunst'], ARRAY['Krieg', 'Konfrontation', 'Konflikt'], ARRAY['diplomatisch', 'Diplomat', 'Diplomatenpass'], NULL, 'common', 3, 'noun', ARRAY['B2', 'politics']),
  (gen_random_uuid(), 'Abkommen', 'agreement', 'das', 'die Abkommen', 'Beide Staaten haben ein bilaterales Abkommen unterzeichnet. — Both states have signed a bilateral agreement.', 'B2', 'politics', 'Politics & Diplomacy', 'accord', 'اتفاقية', '/ˈapkɔmən/', ARRAY['Vertrag', 'Übereinkunft', 'Pakt'], ARRAY['Bruch', 'Kündigung', 'Nichteinhaltung'], ARRAY['abkommen', 'Abkommenspartner', 'Handelsabkommen'], NULL, 'common', 3, 'noun', ARRAY['B2', 'politics', 'diplomacy']),
  (gen_random_uuid(), 'Bündnis', 'alliance', 'das', 'die Bündnisse', 'Das militärische Bündnis feiert in diesem Jahr sein siebzigjähriges Bestehen. — The military alliance is celebrating its seventieth anniversary this year.', 'B2', 'politics', 'Politics & Diplomacy', 'alliance', 'تحالف', '/ˈbʏntnɪs/', ARRAY['Allianz', 'Koalition', 'Bündnispartner'], ARRAY['Feindschaft', 'Gegnerschaft', 'Neutralität'], ARRAY['verbünden', 'Bündnispartner', 'bündnisfrei'], NULL, 'common', 3, 'noun', ARRAY['B2', 'politics']),
  (gen_random_uuid(), 'Koalition', 'coalition', 'die', 'die Koalitionen', 'Die Regierungskoalition hat sich auf wichtige Reformen geeinigt. — The governing coalition has agreed on important reforms.', 'B2', 'politics', 'Politics & Diplomacy', 'coalition', 'ائتلاف', '/koaliˈt͡si̯oːn/', ARRAY['Bündnis', 'Regierungsbündnis', 'Parteienbündnis'], ARRAY['Opposition', 'Alleingang'], ARRAY['Koalitionspartner', 'Koalitionsvertrag', 'Koalitionsregierung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'politics']),
  (gen_random_uuid(), 'Wahlkampf', 'election campaign', 'der', 'die Wahlkämpfe', 'Der Wahlkampf war von hitzigen Debatten um die Steuerpolitik geprägt. — The election campaign was characterized by heated debates about tax policy.', 'B2', 'politics', 'Politics & Diplomacy', 'campagne électorale', 'حملة انتخابية', '/ˈvaːlkampf/', ARRAY['Kampagne', 'Wahlwerbung', 'Wahlpropaganda'], NULL, ARRAY['wählen', 'Wahl', 'Wahlkampfstrategie'], NULL, 'common', 3, 'noun', ARRAY['B2', 'politics']),
