  (gen_random_uuid(), 'Opposition', 'opposition', 'die', 'die Oppositionen', 'Die Opposition kritisierte die Regierungsvorlage scharf. — The opposition sharply criticized the government bill.', 'B2', 'politics', 'Politics & Diplomacy', 'opposition', 'معارضة', '/ɔpoziˈt͡si̯oːn/', ARRAY['Gegenpartei', 'Widerstand', 'Gegenlager'], ARRAY['Koalition', 'Regierung', 'Mehrheit'], ARRAY['oppositionell', 'Oppositionsführer', 'opponieren'], NULL, 'common', 3, 'noun', ARRAY['B2', 'politics']),
  (gen_random_uuid(), 'Botschafter', 'ambassador', 'der', 'die Botschafter', 'Der deutsche Botschafter wurde zu einem Gespräch ins Außenministerium eingeladen. — The German ambassador was invited for a talk at the Foreign Ministry.', 'B2', 'politics', 'Politics & Diplomacy', 'ambassadeur', 'سفير', '/ˈboːtʃaftɐ/', ARRAY['Gesandter', 'Diplomat', 'Vertreter'], NULL, ARRAY['Botschaft', 'Botschafterin', 'Botschafterposten'], NULL, 'rare', 3, 'noun', ARRAY['B2', 'politics', 'diplomacy']),
  (gen_random_uuid(), 'Sanktion', 'sanction', 'die', 'die Sanktionen', 'Die internationalen Sanktionen gegen das Land wurden verschärft. — The international sanctions against the country have been tightened.', 'B2', 'politics', 'Politics & Diplomacy', 'sanction', 'عقوبة دولية', '/zaŋkˈt͡si̯oːn/', ARRAY['Strafmaßnahme', 'Embargo', 'Boykott'], ARRAY['Unterstützung', 'Hilfe', 'Förderung'], ARRAY['sanktionieren', 'Sanktionspolitik', 'Sanktionsliste'], NULL, 'common', 4, 'noun', ARRAY['B2', 'politics', 'diplomacy']),
