  (gen_random_uuid(), 'Rücktritt', 'resignation', 'der', 'die Rücktritte', 'Der Minister erklärte seinen Rücktritt aus persönlichen Gründen. — The minister announced his resignation for personal reasons.', 'B2', 'politics', 'Politics & Diplomacy', 'démission', 'استقالة', '/ˈʁʏktʁɪt/', ARRAY['Demission', 'Amtsverzicht', 'Abdankung'], ARRAY['Amtsantritt', 'Ernennung', 'Wahl'], ARRAY['zurücktreten', 'Rücktrittsgesuch', 'rücktrittswillig'], NULL, 'common', 3, 'noun', ARRAY['B2', 'politics']),
