  (gen_random_uuid(), 'Innovation', 'innovation', 'die', 'die Innovationen', 'Technologische Innovationen verändern unsere Arbeitswelt grundlegend. — Technological innovations are fundamentally changing our working world.', 'B2', 'science', 'Science & Technology', 'innovation', 'ابتكار', '/ɪnɔvaˈt͡si̯oːn/', ARRAY['Neuerung', 'Neuheit', 'Weiterentwicklung'], ARRAY['Stagnation', 'Rückschritt', 'Tradition'], ARRAY['innovativ', 'innovieren', 'Innovationskraft'], NULL, 'common', 3, 'noun', ARRAY['B2', 'science', 'tech']),
