  (gen_random_uuid(), 'Verfahren', 'process/method', 'das', 'die Verfahren', 'Das neue Verfahren zur Energiegewinnung ist umweltfreundlicher als herkömmliche Methoden. — The new process for generating energy is more environmentally friendly than conventional methods.', 'B2', 'science', 'Science & Technology', 'procédé/méthode', 'إجراء/طريقة', '/fɛɐˈfaːʁən/', ARRAY['Methode', 'Prozess', 'Prozedur'], NULL, ARRAY['verfahrenstechnisch', 'Verfahrenstechnik', 'Verfahrensablauf'], NULL, 'common', 3, 'noun', ARRAY['B2', 'science', 'tech']),
  (gen_random_uuid(), 'Technologie', 'technology', 'die', 'die Technologien', 'Moderne Technologien ermöglichen eine effizientere Nutzung von Ressourcen. — Modern technologies enable a more efficient use of resources.', 'B2', 'science', 'Science & Technology', 'technologie', 'تكنولوجيا', '/tɛçnoloˈɡiː/', ARRAY['Technik', 'Hightech', 'Spitzentechnik'], NULL, ARRAY['technologisch', 'Technologietransfer', 'Technologieführer'], NULL, 'common', 3, 'noun', ARRAY['B2', 'science', 'tech']),
  (gen_random_uuid(), 'Forschungslabor', 'research laboratory', 'das', 'die Forschungslabore', 'Im Forschungslabor arbeiten Wissenschaftler aus aller Welt zusammen. — Scientists from all over the world work together in the research laboratory.', 'B2', 'science', 'Science & Technology', 'laboratoire de recherche', 'مختبر أبحاث', '/ˈfɔʁʃʊŋslaˌboːʁ/', ARRAY['Labor', 'Forschungseinrichtung', 'Laboreinrichtung'], NULL, ARRAY['Forschung', 'Labor', 'Forschungsteam'], NULL, 'common', 3, 'noun', ARRAY['B2', 'science']),
  (gen_random_uuid(), 'Experiment', 'experiment', 'das', 'die Experimente', 'Das Experiment lieferte eindeutige Ergebnisse für die Theorie. — The experiment provided clear results for the theory.', 'B2', 'science', 'Science & Technology', 'expérience', 'تجربة', '/ɛkspeʁiˈmɛnt/', ARRAY['Versuch', 'Test', 'Versuchsdurchführung'], NULL, ARRAY['experimentieren', 'experimentell', 'Experimentator'], NULL, 'common', 3, 'noun', ARRAY['B2', 'science']),
  (gen_random_uuid(), 'Datenverarbeitung', 'data processing', 'die', NULL, 'Die Datenverarbeitung erfolgt auf Hochleistungsrechnern. — The data processing is carried out on high-performance computers.', 'B2', 'science', 'Science & Technology', 'traitement de données', 'معالجة بيانات', '/ˈdaːtn̩fɛɐˌbaʁbaɪ̯tʊŋ/', ARRAY['EDV', 'Datenanalyse', 'Rechnerverarbeitung'], NULL, ARRAY['Daten', 'verarbeiten', 'Datenverarbeiter'], NULL, 'common', 4, 'noun', ARRAY['B2', 'science', 'tech']),
  (gen_random_uuid(), 'Künstliche Intelligenz', 'artificial intelligence', 'die', NULL, 'Künstliche Intelligenz revolutioniert die Art und Weise, wie wir mit Maschinen interagieren. — Artificial intelligence is revolutionizing the way we interact with machines.', 'B2', 'science', 'Science & Technology', 'intelligence artificielle', 'ذكاء اصطناعي', '/ˈkʏnstlɪçə ʔɪntɛliˈɡɛnt͡s/', ARRAY['KI', 'Maschinelles Lernen', 'Deep Learning'], NULL, ARRAY['künstlich', 'intelligent', 'KI-Forschung'], NULL, 'common', 3, 'expression', ARRAY['B2', 'science', 'tech']),
  (gen_random_uuid(), 'Robotik', 'robotics', 'die', NULL, 'Die Robotik hat in der Fertigungsindustrie zu erheblichen Effizienzsteigerungen geführt. — Robotics has led to significant efficiency gains in the manufacturing industry.', 'B2', 'science', 'Science & Technology', 'robotique', 'علم الروبوتات', '/ʁoˈboːtɪk/', ARRAY['Robotertechnik', 'Robotiktechnik', 'Automatisierungstechnik'], NULL, ARRAY['Roboter', 'robotisch', 'Robotiksystem'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'science', 'tech']),
