  (gen_random_uuid(), 'Aktie', 'share/stock', 'die', 'die Aktien', 'Der Wert seiner Aktien ist im letzten Jahr deutlich gestiegen. — The value of his shares has increased significantly in the past year.', 'B2', 'finance', 'Finance & Economics', 'action', 'سهم', '/ˈakti̯ə/', ARRAY['Wertpapier', 'Anteilsschein', 'Effekte'], NULL, ARRAY['Aktiengesellschaft', 'Aktionär', 'Aktienmarkt'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance']),
  (gen_random_uuid(), 'Inflation', 'inflation', 'die', 'die Inflationen', 'Die Inflation liegt derzeit bei über fünf Prozent und belastet die Verbraucher. — Inflation is currently at over five percent and is burdening consumers.', 'B2', 'finance', 'Finance & Economics', 'inflation', 'تضخم', '/ɪnflaˈt͡si̯oːn/', ARRAY['Geldentwertung', 'Preissteigerung', 'Teuerung'], ARRAY['Deflation', 'Preisstabilität', 'Stagnation'], ARRAY['inflationär', 'Inflationsrate', 'inflationsbereinigt'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance', 'economics']),
  (gen_random_uuid(), 'Haushalt', 'budget/household', 'der', 'die Haushalte', 'Der Bundeshaushalt sieht Einsparungen in Höhe von 20 Milliarden Euro vor. — The federal budget provides for savings of 20 billion euros.', 'B2', 'finance', 'Finance & Economics', 'budget', 'ميزانية', '/ˈhaʊ̯shalt/', ARRAY['Etat', 'Budget', 'Finanzplan'], ARRAY['Defizit', 'Schulden'], ARRAY['haushalten', 'Haushaltsplan', 'Haushaltsjahr'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance']),
  (gen_random_uuid(), 'Steuer', 'tax', 'die', 'die Steuern', 'Die Steuern auf Einkommen wurden in diesem Jahr gesenkt. — Taxes on income were reduced this year.', 'B2', 'finance', 'Finance & Economics', 'impôt', 'ضريبة', '/ˈʃtɔʏ̯ɐ/', ARRAY['Abgabe', 'Steuerabgabe', 'Steuerlast'], ARRAY['Steuerbefreiung', 'Steuererleichterung'], ARRAY['steuerlich', 'Steuerzahler', 'Steuererklärung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance']),
  (gen_random_uuid(), 'Zins', 'interest', 'der', 'die Zinsen', 'Die Zinsen für Immobilienkredite sind in den letzten Monaten gestiegen. — The interest rates for real estate loans have risen in recent months.', 'B2', 'finance', 'Finance & Economics', 'intérêt', 'فائدة', '/t͡sɪns/', ARRAY['Zinssatz', 'Leitzins', 'Verzinsung'], NULL, ARRAY['verzinsen', 'Zinspolitik', 'Zinsänderung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance']),
  (gen_random_uuid(), 'Anleihe', 'bond', 'die', 'die Anleihen', 'Staatsanleihen gelten als sichere Geldanlage, bringen aber meist niedrige Zinsen. — Government bonds are considered a safe investment but usually yield low interest.', 'B2', 'finance', 'Finance & Economics', 'obligation', 'سند', '/ˈanlaɪ̯ə/', ARRAY['Obligation', 'Rentenpapier', 'Schuldverschreibung'], NULL, ARRAY['Anleihenmarkt', 'Staatsanleihe', 'Unternehmensanleihe'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'finance']),
  (gen_random_uuid(), 'Investor', 'investor', 'der', 'die Investoren', 'Internationale Investoren zeigen großes Interesse an dem Startup. — International investors are showing great interest in the startup.', 'B2', 'finance', 'Finance & Economics', 'investisseur', 'مستثمر', '/ɪnˈvɛstoːɐ̯/', ARRAY['Kapitalgeber', 'Anleger', 'Geldgeber'], ARRAY['Kreditnehmer', 'Schuldner'], ARRAY['investieren', 'Investition', 'Investorengruppe'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance']),
