  (gen_random_uuid(), 'Börse', 'stock exchange', 'die', 'die Börsen', 'Die Börse reagierte nervös auf die Ankündigung der Zinserhöhung. — The stock exchange reacted nervously to the announcement of the interest rate hike.', 'B2', 'finance', 'Finance & Economics', 'bourse', 'بورصة', '/ˈbœʁzə/', ARRAY['Aktienmarkt', 'Finanzmarkt', 'Wertpapiermarkt'], NULL, ARRAY['börsennotiert', 'Börsenkurs', 'Börsengang'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance']),
  (gen_random_uuid(), 'Währung', 'currency', 'die', 'die Währungen', 'Der Euro ist die gemeinsame Währung von 20 europäischen Ländern. — The euro is the common currency of 20 European countries.', 'B2', 'finance', 'Finance & Economics', 'monnaie/devise', 'عملة', '/ˈvɛːʁʊŋ/', ARRAY['Devisen', 'Geldwährung', 'Zahlungsmittel'], NULL, ARRAY['währungspolitisch', 'Währungsunion', 'Währungsreform'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance']),
  (gen_random_uuid(), 'Konjunktur', 'economic cycle', 'die', 'die Konjunkturen', 'Die Konjunktur zeigt Anzeichen einer Abschwächung. — The economy is showing signs of a slowdown.', 'B2', 'finance', 'Finance & Economics', 'conjoncture', 'دورة اقتصادية', '/kɔnjʊŋkˈtuːɐ̯/', ARRAY['Wirtschaftslage', 'Wirtschaftsentwicklung', 'Wirtschaftsklima'], ARRAY['Rezession', 'Depression'], ARRAY['konjunkturell', 'Konjunkturpaket', 'Konjunkturprognose'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'finance', 'economics']),
  (gen_random_uuid(), 'Bruttoinlandsprodukt', 'gross domestic product', 'das', 'die Bruttoinlandsprodukte', 'Das Bruttoinlandsprodukt ist im zweiten Quartal um 0,3 Prozent gewachsen. — The gross domestic product grew by 0.3 percent in the second quarter.', 'B2', 'finance', 'Finance & Economics', 'produit intérieur brut', 'ناتج محلي إجمالي', '/ˈbʁʊtɔɪnlant͡spʁoˌdʊkt/', ARRAY['BIP', 'Wirtschaftsleistung', 'Volkseinkommen'], NULL, ARRAY['brutto', 'Inland', 'Produkt'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'finance', 'economics']),
  (gen_random_uuid(), 'Subvention', 'subsidy', 'die', 'die Subventionen', 'Die Regierung kürzt die Subventionen für fossile Brennstoffe. — The government is cutting subsidies for fossil fuels.', 'B2', 'finance', 'Finance & Economics', 'subvention', 'إعانة مالية', '/zʊpvɛnˈt͡si̯oːn/', ARRAY['Förderung', 'Zuschuss', 'Beihilfe'], ARRAY['Streichung', 'Kürzung'], ARRAY['subventionieren', 'Subventionsabbau', 'Subventionspolitik'], NULL, 'common', 4, 'noun', ARRAY['B2', 'finance']),
