  (gen_random_uuid(), 'Rente', 'pension', 'die', 'die Renten', 'Die gesetzliche Rente reicht vielen Senioren nicht zum Leben aus. — The statutory pension is not enough for many seniors to live on.', 'B2', 'finance', 'Finance & Economics', 'retraite/pension', 'معاش تقاعدي', '/ˈʁɛntə/', ARRAY['Altersvorsorge', 'Pension', 'Ruhegehalt'], NULL, ARRAY['rentenberechtigt', 'Rentner', 'Rentenversicherung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance']),
  (gen_random_uuid(), 'Vermögen', 'assets/fortune', 'das', 'die Vermögen', 'Sein Vermögen wird auf mehrere Millionen Euro geschätzt. — His fortune is estimated at several million euros.', 'B2', 'finance', 'Finance & Economics', 'fortune/patrimoine', 'ثروة', '/fɛɐˈmøːɡən/', ARRAY['Reichtum', 'Vermögenswerte', 'Kapital'], ARRAY['Schulden', 'Armut', 'Verschuldung'], ARRAY['vermögend', 'Vermögenssteuer', 'Vermögensaufbau'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance']),
  (gen_random_uuid(), 'Kredit', 'credit/loan', 'der', 'die Kredite', 'Die Bank hat ihm einen Kredit für den Hauskauf bewilligt. — The bank approved a loan for him to buy a house.', 'B2', 'finance', 'Finance & Economics', 'crédit', 'قرض', '/kʁeˈdiːt/', ARRAY['Darlehen', 'Anleihe', 'Finanzierung'], ARRAY['Schulden', 'Belastung'], ARRAY['kreditieren', 'Kreditinstitut', 'Kreditwürdigkeit'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance']),
  (gen_random_uuid(), 'Wirtschaftswachstum', 'economic growth', 'das', NULL, 'Das Wirtschaftswachstum hat sich im letzten Jahr deutlich verlangsamt. — Economic growth has slowed significantly in the past year.', 'B2', 'finance', 'Finance & Economics', 'croissance économique', 'نمو اقتصادي', '/ˈvɪʁtʃaft͡sˌvakstuːm/', ARRAY['Konjunkturwachstum', 'Expansion', 'Wachstum'], ARRAY['Rezession', 'Schrumpfung', 'Stagnation'], ARRAY['Wirtschaft', 'wachsen', 'Wachstumsbranche'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance', 'economics']),
  (gen_random_uuid(), 'Finanzamt', 'tax office', 'das', 'die Finanzämter', 'Das Finanzamt hat die Steuererklärung geprüft und eine Rückerstattung bewilligt. — The tax office reviewed the tax return and approved a refund.', 'B2', 'finance', 'Finance & Economics', 'administration fiscale', 'مكتب الضرائب', '/fiˈnant͡sʔamt/', ARRAY['Steuerbehörde', 'Finanzbehörde', 'Steueramt'], NULL, ARRAY['Finanz', 'Amt', 'Finanzverwaltung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance']),
  (gen_random_uuid(), 'Schulden', 'debt', 'die', NULL, 'Die öffentlichen Schulden sind während der Krise weiter gestiegen. — Public debt has continued to rise during the crisis.', 'B2', 'finance', 'Finance & Economics', 'dettes', 'ديون', '/ˈʃʊldn̩/', ARRAY['Verbindlichkeiten', 'Verschuldung', 'Passiva'], ARRAY['Vermögen', 'Guthaben', 'Erspartes'], ARRAY['verschulden', 'Schuldner', 'schuldenfrei'], NULL, 'common', 3, 'noun', ARRAY['B2', 'finance']);
INSERT INTO public.vocabulary (id, german_word, english_translation, article, plural, example_sentence, level, category, theme, french_translation, arabic_translation, ipa, synonyms, antonyms, word_family, verb_forms, frequency, difficulty_score, word_type, tags) VALUES
  (gen_random_uuid(), 'Berichterstattung', 'reporting', 'die', 'die Berichterstattungen', 'Die Berichterstattung über die Klimakonferenz war umfassend und ausgewogen. — The reporting on the climate conference was comprehensive and balanced.', 'B2', 'media', 'Media & Journalism', 'reportage/couverture médiatique', 'تغطية إخبارية', '/bəˈʁɪçtʔɛɐˌʃtatʊŋ/', ARRAY['Reportage', 'Medienbericht', 'Nachrichtenbericht'], ARRAY['Zensur', 'Verschweigung'], ARRAY['berichten', 'Bericht', 'Berichterstatter'], NULL, 'common', 3, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Redaktion', 'editorial office', 'die', 'die Redaktionen', 'Die Redaktion der Zeitung arbeitet rund um die Uhr an der aktuellen Ausgabe. — The newspaper''s editorial office works around the clock on the current edition.', 'B2', 'media', 'Media & Journalism', 'rédaction', 'هيئة تحرير', '/ʁedakˈt͡si̯oːn/', ARRAY['Redaktionsteam', 'Redaktionsstab', 'Schriftleitung'], NULL, ARRAY['Redakteur', 'redaktionell', 'Redaktionsschluss'], NULL, 'common', 3, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Journalismus', 'journalism', 'der', NULL, 'Unabhängiger Journalismus ist eine wichtige Säule der Demokratie. — Independent journalism is an important pillar of democracy.', 'B2', 'media', 'Media & Journalism', 'journalisme', 'صحافة', '/ʒʊʁnaˈlɪsmʊs/', ARRAY['Pressewesen', 'Publizistik', 'Medienarbeit'], ARRAY['Propaganda', 'Desinformation'], ARRAY['Journalist', 'journalistisch', 'Journalistenschule'], NULL, 'common', 3, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Medien', 'media', 'die', NULL, 'Die sozialen Medien haben die Art der Kommunikation grundlegend verändert. — Social media have fundamentally changed the way we communicate.', 'B2', 'media', 'Media & Journalism', 'médias', 'وسائل إعلام', '/ˈmeːdi̯ən/', ARRAY['Massenmedien', 'Kommunikationsmittel', 'Presse'], NULL, ARRAY['medial', 'Medienlandschaft', 'Medienunternehmen'], NULL, 'common', 3, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Schlagzeile', 'headline', 'die', 'die Schlagzeilen', 'Die Schlagzeile auf der Titelseite sorgte für großes Aufsehen. — The headline on the front page caused a great stir.', 'B2', 'media', 'Media & Journalism', 'gros titre', 'عنوان رئيسي', '/ˈʃlaːkˌt͡saɪ̯lə/', ARRAY['Überschrift', 'Titelzeile', 'Headline'], NULL, ARRAY['Schlag', 'Zeile', 'schlagzeilenträchtig'], NULL, 'common', 3, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Presse', 'press', 'die', NULL, 'Die Presse wurde zur Pressekonferenz des Bundeskanzlers eingeladen. — The press was invited to the Chancellor''s press conference.', 'B2', 'media', 'Media & Journalism', 'presse', 'صحافة/إعلام', '/ˈpʁɛsə/', ARRAY['Medien', 'Nachrichtenmedien', 'Printmedien'], NULL, ARRAY['Pressesprecher', 'Pressemitteilung', 'Pressefreiheit'], NULL, 'common', 3, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Interview', 'interview', 'das', 'die Interviews', 'In einem Interview äußerte sich der Minister zu den aktuellen Reformen. — In an interview, the minister commented on the current reforms.', 'B2', 'media', 'Media & Journalism', 'entretien/interview', 'مقابلة', '/ˈɪntɐvjuː/', ARRAY['Gespräch', 'Befragung', 'Aussprache'], NULL, ARRAY['interviewen', 'Interviewpartner', 'Interviewreihe'], NULL, 'common', 3, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Feuilleton', 'arts section', 'das', 'die Feuilletons', 'Im Feuilleton der Zeitung werden aktuelle Kulturthemen besprochen. — The arts section of the newspaper discusses current cultural topics.', 'B2', 'media', 'Media & Journalism', 'page culturelle', 'ملحق ثقافي', '/fœjəˈtɔ̃/', ARRAY['Kulturteil', 'Kulturseite', 'Kulturressort'], NULL, ARRAY['feuilletonistisch', 'Feuilletonredakteur', 'Feuilletonbeitrag'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Nachrichtensendung', 'news broadcast', 'die', 'die Nachrichtensendungen', 'Die Nachrichtensendung beginnt um 20 Uhr mit den wichtigsten Meldungen des Tages. — The news broadcast begins at 8 p.m. with the most important news of the day.', 'B2', 'media', 'Media & Journalism', 'journal télévisé', 'نشرة أخبار', '/ˈnaːxʁɪçtn̩ˌzɛndʊŋ/', ARRAY['Nachrichten', 'Tagesschau', 'Nachrichtenprogramm'], NULL, ARRAY['Nachricht', 'Sendung', 'Nachrichtenredaktion'], NULL, 'common', 3, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Zeitung', 'newspaper', 'die', 'die Zeitungen', 'Die Zeitung erscheint sowohl in gedruckter Form als auch online. — The newspaper is published both in print and online.', 'B2', 'media', 'Media & Journalism', 'journal', 'جريدة', '/ˈt͡saɪ̯tʊŋ/', ARRAY['Tageszeitung', 'Blatt', 'Gazette'], NULL, ARRAY['Zeitungsartikel', 'Zeitungsverlag', 'Zeitungsausträger'], NULL, 'common', 3, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Korrespondent', 'correspondent', 'der', 'die Korrespondenten', 'Der Korrespondent berichtet live aus dem Krisengebiet. — The correspondent reports live from the crisis zone.', 'B2', 'media', 'Media & Journalism', 'correspondant', 'مراسل', '/kɔʁɛspɔnˈdɛnt/', ARRAY['Reporter', 'Berichterstatter', 'Journalist'], NULL, ARRAY['korrespondieren', 'Korrespondenz', 'Korrespondentennetz'], NULL, 'common', 3, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Rundfunk', 'broadcasting', 'der', NULL, 'Der öffentlich-rechtliche Rundfunk finanziert sich durch Rundfunkgebühren. — Public broadcasting is financed through broadcasting fees.', 'B2', 'media', 'Media & Journalism', 'radiodiffusion', 'إذاعة', '/ˈʁʊntfʊŋk/', ARRAY['Hörfunk', 'Radio', 'Sendebetrieb'], NULL, ARRAY['Rundfunkanstalt', 'Rundfunkbeitrag', 'Rundfunkrat'], NULL, 'common', 3, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Zensur', 'censorship', 'die', NULL, 'Die Zensur der Presse ist in demokratischen Ländern nicht mit der Pressefreiheit vereinbar. — Censorship of the press is incompatible with press freedom in democratic countries.', 'B2', 'media', 'Media & Journalism', 'censure', 'رقابة', '/t͡sɛnˈzuːɐ̯/', ARRAY['Kontrolle', 'Überwachung', 'Bevormundung'], ARRAY['Pressefreiheit', 'Meinungsfreiheit', 'Redefreiheit'], ARRAY['zensieren', 'Zensor', 'zensurfrei'], NULL, 'common', 4, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Trend', 'trend', 'der', 'die Trends', 'Der Trend zu nachhaltigen Produkten setzt sich in allen Branchen fort. — The trend toward sustainable products continues across all industries.', 'B2', 'media', 'Media & Journalism', 'tendance', 'اتجاه/موضة', '/tʁɛnt/', ARRAY['Entwicklung', 'Strömung', 'Tendenz'], NULL, ARRAY['trendy', 'Trendsetter', 'Trendwende'], NULL, 'common', 3, 'noun', ARRAY['B2', 'media']),
  (gen_random_uuid(), 'Verleger', 'publisher', 'der', 'die Verleger', 'Der Verleger entscheidet, welche Bücher in seinem Verlag erscheinen. — The publisher decides which books are published in his publishing house.', 'B2', 'media', 'Media & Journalism', 'éditeur', 'ناشر', '/fɛɐˈleːɡɐ/', ARRAY['Herausgeber', 'Verlagseigner', 'Buchverleger'], NULL, ARRAY['Verlag', 'verlegen', 'Verlagsprogramm'], NULL, 'rare', 3, 'noun', ARRAY['B2', 'media']);
INSERT INTO public.vocabulary (id, german_word, english_translation, article, plural, example_sentence, level, category, theme, french_translation, arabic_translation, ipa, synonyms, antonyms, word_family, verb_forms, frequency, difficulty_score, word_type, tags) VALUES
  (gen_random_uuid(), 'Vorschrift', 'regulation', 'die', 'die Vorschriften', 'Die Vorschriften für die Lebensmittelkennzeichnung wurden EU-weit vereinheitlicht. — The regulations for food labeling have been standardized throughout the EU.', 'B2', 'law', 'Law & Regulations', 'règlement/prescription', 'لائحة', '/ˈfoːɐ̯ʃʁɪft/', ARRAY['Regelung', 'Bestimmung', 'Richtlinie'], ARRAY['Freiheit', 'Willkür'], ARRAY['vorschreiben', 'vorschriftsmäßig', 'Vorschriftenverstoß'], NULL, 'common', 3, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Gesetzgebung', 'legislation', 'die', NULL, 'Die Gesetzgebung liegt in der Verantwortung des Parlaments. — The legislation is the responsibility of parliament.', 'B2', 'law', 'Law & Regulations', 'législation', 'تشريع', '/ɡəˈzɛt͡sɡeːbʊŋ/', ARRAY['Rechtsetzung', 'Legislative', 'Normsetzung'], NULL, ARRAY['Gesetz', 'gesetzgeberisch', 'Gesetzgebungsverfahren'], NULL, 'common', 4, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Verordnung', 'ordinance', 'die', 'die Verordnungen', 'Die neue Verordnung zur Eindämmung der Pandemie tritt morgen in Kraft. — The new ordinance to contain the pandemic comes into force tomorrow.', 'B2', 'law', 'Law & Regulations', 'ordonnance/règlement', 'أمر قانوني', '/fɛɐˈʔɔʁdnʊŋ/', ARRAY['Erlass', 'Anordnung', 'Dekret'], NULL, ARRAY['verordnen', 'Verordnungsentwurf', 'Verordnungsgeber'], NULL, 'common', 3, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Rechtsschutz', 'legal protection', 'der', NULL, 'Jeder Bürger hat Anspruch auf Rechtsschutz vor Gericht. — Every citizen is entitled to legal protection in court.', 'B2', 'law', 'Law & Regulations', 'protection juridique', 'حماية قانونية', '/ˈʁɛçt͡sʃʊt͡s/', ARRAY['Rechtsbeistand', 'Rechtshilfe', 'Rechtssicherheit'], ARRAY['Rechtlosigkeit', 'Willkür'], ARRAY['Recht', 'Schutz', 'rechtsschutzsuchend'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Anwalt', 'lawyer', 'der', 'die Anwälte', 'Der Anwalt vertrat seinen Mandanten vor dem Oberlandesgericht. — The lawyer represented his client before the Higher Regional Court.', 'B2', 'law', 'Law & Regulations', 'avocat', 'محامٍ', '/ˈanvalt/', ARRAY['Rechtsanwalt', 'Jurist'], NULL, ARRAY['anwaltlich', 'Anwaltskanzlei', 'Anwaltsberuf'], NULL, 'common', 3, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Urteil', 'judgment', 'das', 'die Urteile', 'Das Urteil des Gerichts wurde von allen Prozessbeteiligten akzeptiert. — The court''s judgment was accepted by all parties to the proceedings.', 'B2', 'law', 'Law & Regulations', 'jugement/arrêt', 'حكم قضائي', '/ˈʊʁtaɪ̯l/', ARRAY['Entscheidung', 'Spruch', 'Gerichtsentscheid'], ARRAY['Freispruch', 'Ablehnung'], ARRAY['urteilen', 'Urteilsverkündung', 'urteilsfähig'], NULL, 'common', 3, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Richter', 'judge', 'der', 'die Richter', 'Der Richter verlas das Urteil im Namen des Volkes. — The judge read the verdict in the name of the people.', 'B2', 'law', 'Law & Regulations', 'juge', 'قاضٍ', '/ˈʁɪçtɐ/', ARRAY['Vorsitzender', 'Gerichtsherr', 'Rechtsprecher'], NULL, ARRAY['richten', 'Richteramt', 'Richterkollegium'], NULL, 'common', 3, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Prozess', 'trial/lawsuit', 'der', 'die Prozesse', 'Der Prozess gegen den Angeklagten wurde wegen fehlender Beweise eingestellt. — The trial against the defendant was dropped due to lack of evidence.', 'B2', 'law', 'Law & Regulations', 'procès', 'دعوى قضائية', '/pʁoˈt͡sɛs/', ARRAY['Gerichtsverfahren', 'Verhandlung', 'Rechtsstreit'], ARRAY['Vergleich', 'Einigung'], ARRAY['prozessieren', 'Prozessordnung', 'Prozesspartei'], NULL, 'common', 3, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Straftat', 'criminal offense', 'die', 'die Straftaten', 'Die Zahl der Straftaten ist im Vergleich zum Vorjahr gesunken. — The number of criminal offenses has decreased compared to the previous year.', 'B2', 'law', 'Law & Regulations', 'infraction pénale', 'جريمة', '/ˈʃtʁaːtˌtaːt/', ARRAY['Vergehen', 'Delikt', 'Verbrechen'], NULL, ARRAY['strafen', 'Straftäter', 'strafrechtlich'], NULL, 'common', 3, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Verfassung', 'constitution', 'die', 'die Verfassungen', 'Das Grundgesetz ist die Verfassung der Bundesrepublik Deutschland. — The Basic Law is the constitution of the Federal Republic of Germany.', 'B2', 'law', 'Law & Regulations', 'constitution', 'دستور', '/fɛɐˈfasʊŋ/', ARRAY['Grundgesetz', 'Staatsverfassung', 'Verfassungsordnung'], ARRAY['Willkür', 'Diktatur'], ARRAY['verfassen', 'Verfassungsgericht', 'verfassungswidrig'], NULL, 'common', 4, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Rechtsanwalt', 'attorney', 'der', 'die Rechtsanwälte', 'Der Rechtsanwalt berät seine Klienten in allen rechtlichen Fragen. — The attorney advises his clients on all legal matters.', 'B2', 'law', 'Law & Regulations', 'avocat', 'محامٍ', '/ˈʁɛçt͡sʔanˌvalt/', ARRAY['Anwalt', 'Rechtsbeistand', 'Justiziar'], NULL, ARRAY['Recht', 'Anwalt', 'Rechtsanwaltskammer'], NULL, 'common', 3, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Haftung', 'liability', 'die', 'die Haftungen', 'Der Hersteller übernimmt die Haftung für fehlerhafte Produkte. — The manufacturer assumes liability for defective products.', 'B2', 'law', 'Law & Regulations', 'responsabilité', 'مسؤولية', '/ˈhaftʊŋ/', ARRAY['Verantwortung', 'Garantie', 'Gewährleistung'], NULL, ARRAY['haften', 'Haftpflicht', 'haftungsfrei'], NULL, 'common', 3, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Vertragsbruch', 'breach of contract', 'der', 'die Vertragsbrüche', 'Der Vertragsbruch führte zu einer Schadensersatzklage. — The breach of contract led to a claim for damages.', 'B2', 'law', 'Law & Regulations', 'rupture de contrat', 'خرق العقد', '/fɛɐˈtʁaːksbʁʊx/', ARRAY['Pflichtverletzung', 'Vertragsverletzung'], ARRAY['Vertragstreue', 'Vertragserfüllung'], ARRAY['Vertrag', 'Bruch', 'vertragsbrüchig'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Klage', 'lawsuit', 'die', 'die Klagen', 'Die Klage wurde vom Gericht wegen fehlender Zuständigkeit abgewiesen. — The lawsuit was dismissed by the court for lack of jurisdiction.', 'B2', 'law', 'Law & Regulations', 'plainte/action en justice', 'دعوى', '/ˈklaːɡə/', ARRAY['Rechtsstreit', 'Prozess', 'Beschwerde'], ARRAY['Vergleich', 'Einigung'], ARRAY['klagen', 'Kläger', 'Klagegrund'], NULL, 'common', 3, 'noun', ARRAY['B2', 'law']),
  (gen_random_uuid(), 'Frist', 'deadline', 'die', 'die Fristen', 'Die Frist für die Einreichung der Unterlagen läuft in drei Tagen ab. — The deadline for submitting the documents expires in three days.', 'B2', 'law', 'Law & Regulations', 'délai', 'موعد نهائي', '/fʁɪst/', ARRAY['Termin', 'Zeitlimit', 'Fristablauf'], NULL, ARRAY['fristgemäß', 'Fristverlängerung', 'fristlos'], NULL, 'common', 3, 'noun', ARRAY['B2', 'law', 'business']);
INSERT INTO public.vocabulary (id, german_word, english_translation, article, plural, example_sentence, level, category, theme, french_translation, arabic_translation, ipa, synonyms, antonyms, word_family, verb_forms, frequency, difficulty_score, word_type, tags) VALUES
  (gen_random_uuid(), 'Psychologie', 'psychology', 'die', NULL, 'Die Psychologie befasst sich mit dem menschlichen Erleben und Verhalten. — Psychology deals with human experience and behavior.', 'B2', 'health', 'Health & Psychology', 'psychologie', 'علم النفس', '/psyçoloˈɡiː/', ARRAY['Seelenkunde', 'Verhaltenswissenschaft', 'Tiefenpsychologie'], NULL, ARRAY['psychologisch', 'Psychologe', 'Psychologiestudium'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Prävention', 'prevention', 'die', 'die Präventionen', 'Prävention ist besser als Behandlung: Regelmäßige Vorsorgeuntersuchungen sind wichtig. — Prevention is better than cure: regular check-ups are important.', 'B2', 'health', 'Health & Psychology', 'prévention', 'وقاية', '/pʁɛvɛnˈt͡si̯oːn/', ARRAY['Vorbeugung', 'Prophylaxe', 'Vorsorge'], ARRAY['Behandlung', 'Therapie', 'Nachsorge'], ARRAY['präventiv', 'vorbeugen', 'Präventionsmaßnahme'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Therapie', 'therapy', 'die', 'die Therapien', 'Die Therapie hat dem Patienten geholfen, seine Angststörung zu überwinden. — The therapy helped the patient overcome his anxiety disorder.', 'B2', 'health', 'Health & Psychology', 'thérapie', 'علاج', '/teʁaˈpiː/', ARRAY['Behandlung', 'Heilbehandlung', 'Therapieform'], NULL, ARRAY['therapeutisch', 'Therapeut', 'Therapiemethode'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Diagnose', 'diagnosis', 'die', 'die Diagnosen', 'Die Diagnose wurde nach mehreren medizinischen Tests gestellt. — The diagnosis was made after several medical tests.', 'B2', 'health', 'Health & Psychology', 'diagnostic', 'تشخيص', '/diaˈɡnoːzə/', ARRAY['Befund', 'Feststellung', 'Erkennung'], NULL, ARRAY['diagnostizieren', 'diagnostisch', 'Diagnoseverfahren'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Symptom', 'symptom', 'das', 'die Symptome', 'Zu den Symptomen der Krankheit gehören Fieber und Husten. — Symptoms of the disease include fever and cough.', 'B2', 'health', 'Health & Psychology', 'symptôme', 'عرض', '/zʏmpˈtoːm/', ARRAY['Anzeichen', 'Krankheitszeichen', 'Merkmal'], NULL, ARRAY['symptomatisch', 'Symptomatik', 'symptomfrei'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Depression', 'depression', 'die', 'die Depressionen', 'Immer mehr junge Menschen leiden unter Depressionen. — More and more young people suffer from depression.', 'B2', 'health', 'Health & Psychology', 'dépression', 'اكتئاب', '/depʁɛˈsi̯oːn/', ARRAY['Niedergeschlagenheit', 'Schwermut', 'Melancholie'], ARRAY['Freude', 'Glück', 'Optimismus'], ARRAY['depressiv', 'deprimieren', 'Depressionsbehandlung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Krankenkasse', 'health insurance', 'die', 'die Krankenkassen', 'Die Krankenkasse übernimmt die Kosten für die Vorsorgeuntersuchung. — The health insurance covers the costs of the check-up.', 'B2', 'health', 'Health & Psychology', 'caisse d''assurance maladie', 'شركة تأمين صحي', '/ˈkʁaŋkn̩ˌkasə/', ARRAY['Versicherung', 'Krankenversicherung', 'Gesundheitskasse'], NULL, ARRAY['Kranken', 'Kasse', 'Krankenversicherungsbeitrag'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Ernährung', 'nutrition', 'die', NULL, 'Eine ausgewogene Ernährung ist wichtig für die Gesundheit. — A balanced diet is important for health.', 'B2', 'health', 'Health & Psychology', 'nutrition', 'تغذية', '/ɛɐˈnɛːʁʊŋ/', ARRAY['Nahrung', 'Essen', 'Kost'], NULL, ARRAY['ernähren', 'Ernährungsberater', 'Ernährungsweise'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Rehabilitation', 'rehabilitation', 'die', 'die Rehabilitationen', 'Nach dem Unfall war eine lange Rehabilitation notwendig. — After the accident, a long rehabilitation was necessary.', 'B2', 'health', 'Health & Psychology', 'rééducation/réadaptation', 'إعادة تأهيل', '/ʁehabilitˈt͡si̯oːn/', ARRAY['Reha', 'Wiedereingliederung', 'Genesung'], NULL, ARRAY['rehabilitieren', 'Rehazentrum', 'Rehamaßnahme'], NULL, 'common', 4, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Stress', 'stress', 'der', NULL, 'Stress am Arbeitsplatz kann zu ernsthaften gesundheitlichen Problemen führen. — Stress at the workplace can lead to serious health problems.', 'B2', 'health', 'Health & Psychology', 'stress', 'توتر/إجهاد', '/ʃtʁɛs/', ARRAY['Belastung', 'Anspannung', 'Druck'], ARRAY['Entspannung', 'Ruhe', 'Gelassenheit'], ARRAY['stressig', 'stressen', 'Stressbewältigung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Impfung', 'vaccination', 'die', 'die Impfungen', 'Die Impfung schützt vor schweren Krankheitsverläufen. — The vaccination protects against severe courses of the disease.', 'B2', 'health', 'Health & Psychology', 'vaccination', 'تطعيم', '/ˈʔɪmpfʊŋ/', ARRAY['Schutzimpfung', 'Vakzinierung', 'Immunisierung'], ARRAY['Krankheit', 'Infektion'], ARRAY['impfen', 'Impstoff', 'Impfdurchbruch'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Krankheit', 'illness', 'die', 'die Krankheiten', 'Die Krankheit wurde frühzeitig erkannt und konnte erfolgreich behandelt werden. — The illness was detected early and could be treated successfully.', 'B2', 'health', 'Health & Psychology', 'maladie', 'مرض', '/ˈkʁaŋkhaɪ̯t/', ARRAY['Erkrankung', 'Leiden', 'Gebrechen'], ARRAY['Gesundheit', 'Wohlbefinden', 'Genesung'], ARRAY['krank', 'erkranken', 'Krankheitsbild'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Operation', 'surgery', 'die', 'die Operationen', 'Die Operation verlief ohne Komplikationen. — The surgery went without complications.', 'B2', 'health', 'Health & Psychology', 'opération chirurgicale', 'عملية جراحية', '/ʔɔpəʁaˈt͡si̯oːn/', ARRAY['Eingriff', 'OP', 'chirurgischer Eingriff'], NULL, ARRAY['operieren', 'Operationssaal', 'Operationstisch'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
  (gen_random_uuid(), 'Patient', 'patient', 'der', 'die Patienten', 'Der Patient wurde nach der Behandlung aus dem Krankenhaus entlassen. — The patient was discharged from the hospital after treatment.', 'B2', 'health', 'Health & Psychology', 'patient', 'مريض', '/paˈt͡si̯ɛnt/', ARRAY['Kranker', 'Behandelter', 'Klient'], ARRAY['Arzt', 'Personal'], ARRAY['Patientenakte', 'Patientenzimmer', 'Patientenverfügung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'health']),
