  (gen_random_uuid(), 'Umweltschutz', 'environmental protection', 'der', NULL, 'Umweltschutz beginnt im Alltag mit kleinen Veränderungen. — Environmental protection begins in everyday life with small changes.', 'B2', 'environment', 'Environment & Sustainability', 'protection de l''environnement', 'حماية البيئة', '/ˈʊmvɛltˌʃʊt͡s/', ARRAY['Naturschutz', 'Klimaschutz', 'Ökologie'], ARRAY['Umweltverschmutzung', 'Zerstörung'], ARRAY['Umwelt', 'schützen', 'Umweltschützer'], NULL, 'common', 3, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Klimawandel', 'climate change', 'der', NULL, 'Der Klimawandel ist eine der größten Herausforderungen unserer Zeit. — Climate change is one of the greatest challenges of our time.', 'B2', 'environment', 'Environment & Sustainability', 'changement climatique', 'تغير المناخ', '/ˈkliːmaˌvandl̩/', ARRAY['Erderwärmung', 'globale Erwärmung', 'Klimaerwärmung'], NULL, ARRAY['Klima', 'Wandel', 'Klimapolitik'], NULL, 'common', 3, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Erneuerbare Energie', 'renewable energy', 'die', 'die erneuerbaren Energien', 'Erneuerbare Energien wie Wind und Sonne werden immer wichtiger. — Renewable energies like wind and sun are becoming increasingly important.', 'B2', 'environment', 'Environment & Sustainability', 'énergie renouvelable', 'طاقة متجددة', '/ɛɐˈnɔɪ̯ɐbaʁə enɛʁˈɡiː/', ARRAY['Ökostrom', 'Grüne Energie', 'Alternativenergie'], ARRAY['Fossile Energie', 'Atomenergie', 'Kohle'], ARRAY['erneuern', 'Energie', 'erneuerbar'], NULL, 'common', 3, 'expression', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Treibhausgas', 'greenhouse gas', 'das', 'die Treibhausgase', 'Treibhausgase sind hauptverantwortlich für die globale Erwärmung. — Greenhouse gases are primarily responsible for global warming.', 'B2', 'environment', 'Environment & Sustainability', 'gaz à effet de serre', 'غاز دفيء', '/ˈtʁaɪ̯phaʊ̯sˌɡaːs/', ARRAY['Kohlendioxid', 'CO₂', 'Klimagas'], NULL, ARRAY['Treibhaus', 'Gas', 'Treibhauseffekt'], NULL, 'common', 4, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Recycling', 'recycling', 'das', NULL, 'Durch Recycling lassen sich wertvolle Rohstoffe wiedergewinnen. — Valuable raw materials can be recovered through recycling.', 'B2', 'environment', 'Environment & Sustainability', 'recyclage', 'إعادة تدوير', '/ʁiˈsaɪ̯klɪŋ/', ARRAY['Wiederverwertung', 'Wiederaufbereitung', 'Kreislaufwirtschaft'], ARRAY['Verschwendung', 'Müllproduktion'], ARRAY['recyceln', 'Recyclingquote', 'Recyclinganlage'], NULL, 'common', 3, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Ökologie', 'ecology', 'die', NULL, 'Die Ökologie untersucht die Wechselwirkungen zwischen Organismen und ihrer Umwelt. — Ecology studies the interactions between organisms and their environment.', 'B2', 'environment', 'Environment & Sustainability', 'écologie', 'علم البيئة', '/økoloˈɡiː/', ARRAY['Umweltwissenschaft', 'Umweltbiologie', 'Naturhaushalt'], NULL, ARRAY['ökologisch', 'Ökologe', 'Ökologiebewegung'], NULL, 'common', 3, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Ressource', 'resource', 'die', 'die Ressourcen', 'Die natürlichen Ressourcen unseres Planeten sind begrenzt. — The natural resources of our planet are limited.', 'B2', 'environment', 'Environment & Sustainability', 'ressource', 'مورد', '/ʁɛˈsʊʁsə/', ARRAY['Rohstoff', 'Reserve', 'Vorrat'], ARRAY['Mangel', 'Knappheit'], ARRAY['ressourcenschonend', 'Ressourcenverbrauch', 'Ressourcenknappheit'], NULL, 'common', 3, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Kohlendioxid', 'carbon dioxide', 'das', NULL, 'Kohlendioxid entsteht bei der Verbrennung fossiler Brennstoffe. — Carbon dioxide is produced when burning fossil fuels.', 'B2', 'environment', 'Environment & Sustainability', 'dioxyde de carbone', 'ثاني أكسيد الكربون', '/koːlənˈdiːʔɔksiːt/', ARRAY['CO₂', 'Treibhausgas', 'Kohlenstoffdioxid'], NULL, ARRAY['Kohlen', 'Dioxid', 'Kohlendioxidausstoß'], NULL, 'common', 3, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Artenschutz', 'species protection', 'der', NULL, 'Der Artenschutz ist ein wichtiges Anliegen von Umweltorganisationen. — Species protection is an important concern of environmental organizations.', 'B2', 'environment', 'Environment & Sustainability', 'protection des espèces', 'حماية الأنواع', '/ˈaːɐ̯tn̩ˌʃʊt͡s/', ARRAY['Naturschutz', 'Biodiversitätsschutz', 'Tierartenschutz'], ARRAY['Artensterben', 'Ausrottung'], ARRAY['Art', 'Schutz', 'Artenschutzabkommen'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Biodiversität', 'biodiversity', 'die', NULL, 'Die Biodiversität in den tropischen Regenwäldern ist besonders hoch. — Biodiversity in tropical rainforests is particularly high.', 'B2', 'environment', 'Environment & Sustainability', 'biodiversité', 'تنوع بيولوجي', '/biodivɛʁziˈtɛːt/', ARRAY['Artenvielfalt', 'Biologische Vielfalt', 'Artenreichtum'], ARRAY['Artenarmut', 'Monokultur'], ARRAY['bio', 'Diversität', 'Biodiversitätsstrategie'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Ökobilanz', 'ecological footprint', 'die', 'die Ökobilanzen', 'Die Ökobilanz des Produkts zeigt eine positive Umweltbilanz. — The ecological footprint of the product shows a positive environmental balance.', 'B2', 'environment', 'Environment & Sustainability', 'bilan écologique', 'ميزانية بيئية', '/ˈøːkobiˌlant͡s/', ARRAY['Umweltbilanz', 'CO₂-Bilanz', 'Klimabilanz'], NULL, ARRAY['Öko', 'Bilanz', 'Ökobilanzerstellung'], NULL, 'rare', 4, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Luftverschmutzung', 'air pollution', 'die', NULL, 'Die Luftverschmutzung in Großstädten stellt ein ernstes Gesundheitsrisiko dar. — Air pollution in large cities poses a serious health risk.', 'B2', 'environment', 'Environment & Sustainability', 'pollution de l''air', 'تلوث الهواء', '/ˈlʊftfɛɐˌʃmʊt͡sʊŋ/', ARRAY['Smog', 'Feinstaubbelastung', 'Luftverunreinigung'], ARRAY['Luftreinheit', 'saubere Luft'], ARRAY['Luft', 'Verschmutzung', 'Luftschadstoff'], NULL, 'common', 3, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Mülltrennung', 'waste separation', 'die', NULL, 'In Deutschland ist Mülltrennung in verschiedenen Farben Standard. — Waste separation in different colors is standard in Germany.', 'B2', 'environment', 'Environment & Sustainability', 'tri des déchets', 'فرز النفايات', '/ˈmʏltʁɛnʊŋ/', ARRAY['Abfalltrennung', 'Abfallsortierung', 'Müllsortierung'], NULL, ARRAY['Müll', 'trennen', 'Mülltonne'], NULL, 'common', 3, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Nachhaltigkeit', 'sustainability', 'die', NULL, 'Nachhaltigkeit bedeutet, die Bedürfnisse der Gegenwart zu befriedigen, ohne die Möglichkeiten künftiger Generationen zu gefährden. — Sustainability means meeting the needs of the present without compromising the opportunities of future generations.', 'B2', 'environment', 'Environment & Sustainability', 'durabilité', 'استدامة', '/ˈnaːxhaltɪçkaɪ̯t/', ARRAY['Zukunftsbeständigkeit', 'Nachhaltige Entwicklung'], ARRAY['Ressourcenverschwendung', 'Kurzlebigkeit'], ARRAY['nachhaltig', 'Nachhaltigkeitsziel', 'nachhaltig wirtschaften'], NULL, 'common', 3, 'noun', ARRAY['B2', 'environment']),
  (gen_random_uuid(), 'Klimaschutz', 'climate protection', 'der', NULL, 'Klimaschutz erfordert ein gemeinsames Handeln aller Länder. — Climate protection requires joint action by all countries.', 'B2', 'environment', 'Environment & Sustainability', 'protection du climat', 'حماية المناخ', '/ˈkliːmaˌʃʊt͡s/', ARRAY['Klimapolitik', 'Emissionsreduktion', 'Klimaneutralität'], ARRAY['Klimazerstörung', 'Erderwärmung'], ARRAY['Klima', 'Schutz', 'Klimaschutzmaßnahme'], NULL, 'common', 3, 'noun', ARRAY['B2', 'environment']);
